-
-  describe("value prop changes", () => {
-    it("re-animates when value changes after initial animation", async () => {
-      const { rerender } = render(
-        <AnimatedCounter value={50} duration={50} />
-      );
-
-      // Complete first animation
-      await act(async () => {
-        triggerIntersection(true);
